mapper.select:
SELECT * FROM biz_house 
WHERE is_deleted = 0 AND status = #{status}

    AND city = #{city}


    AND district = #{district}


    AND house_type LIKE CONCAT('%', #{houseType}, '%')


    AND rent_price >= #{minPrice}


    AND rent_price <= #{maxPrice}


    AND area >= #{minArea}


    AND area <= #{maxArea}


    AND rent_way = #{rentWay}

ORDER BY 

    create_time DESC
    rent_price ASC
    area DESC
    view_count DESC
    create_time DESC
